import { SafeAreaView } from 'react-native-safe-area-context';
import styled, { css } from 'styled-components/native';

import { ContainerProps, HeaderProps, StatusBarIosProps } from './Models';

export const Container = styled(SafeAreaView).attrs<ContainerProps>(() => ({
  edges: ['top', 'left', 'right'] as const,
}))<ContainerProps>`
  flex: 1;

  ${({ theme, bgColor }) => css`
    background: ${theme.colors[bgColor]};
  `}
`;

const Header = styled.View<HeaderProps>`
  flex-direction: row;
  align-items: center;
  padding: 16px 20px;

  ${({ theme, bgColor }) => css`
    background: ${theme.colors[bgColor]};
  `}
`;

const TitleContainer = styled.View`
  flex: 1;
  align-items: center;
`;

const StatusBarIos = styled.SafeAreaView<StatusBarIosProps>`
  flex: 0;

  ${({ theme, bgColor }) => css`
    background: ${theme.colors[bgColor]};
  `}
`;

export const Overlay = styled.View`
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background-color: rgba(0, 0, 0, 0.6);
  z-index: 10;
  pointer-events: auto;
`;

