     1→import { PropsIconsNameCore } from '@semparar/design-system-app';
     2→import { PropsCardTransition } from '@semparar/design-system-app/src/atomic/molecules/CardTransition/Models';
     3→import { propsItemsListCardTransition } from '@semparar/design-system-app/src/atomic/organisms/ListCardTransition/Models';
     4→import { eventSelectContent } from '../../../../constants/functions';
     5→import { moment } from '../../../../services/moment';
     6→import type {
     7→  PointsExtractData,
     8→  PointsTransaction,
     9→  ProcessedExtractData,
    10→  TransactionType,
    11→} from '../models/extract.model';
    12→import { TYPE_LABELS } from '../models/extract.model';
    13→import type { getPointsExtractApi, TransactionDto } from '../api/extract.api';
    14→
    15→const TRANSACTION_TYPE_MAP: Record<string, TransactionType> = {
    16→  CREDIT: 'CREDIT',
    17→  RESCUE: 'RESCUE',
    18→  EXPIRED: 'EXPIRED',
    19→  REFUNDED: 'REFUNDED',
    20→};
    21→
    22→const DEFAULT_PROCESSED_EXTRACT_DATA: ProcessedExtractData = {
    23→  groupedTransactions: [],
    24→  mappedTransactions: [],
    25→};
    26→
    27→function getMappedTransactionType(backendType: string): TransactionType {
    28→  return TRANSACTION_TYPE_MAP[backendType] ?? 'CREDIT';
    29→}
    30→
    31→function getFormattedDateForHeader(dateString: string): string {
    32→  return moment(dateString).format('DD [de] MMMM').toLowerCase();
    33→}
    34→
    35→function getFormattedPointsValue(amount: number, type: TransactionType): string {
    36→  const isPositive = type === 'CREDIT' || type === 'REFUNDED';
    37→  const prefix = isPositive ? '+ ' : '- ';
    38→  return `${prefix}${Math.abs(amount).toLocaleString('pt-BR')} pontos`;
    39→}
    40→
    41→function getTransactionDescription(type: TransactionType): string {
    42→  return TYPE_LABELS[type] || '';
    43→}
    44→
    45→function getCapitalizedText(text: string): string {
    46→  if (!text) return text;
    47→  return text.charAt(0).toUpperCase() + text.slice(1).toLowerCase();
    48→}
    49→
    50→function getTransactionCardItem(
    51→  transaction: PointsTransaction,
    52→): PropsCardTransition {
    53→  const isPositive = transaction.type === 'CREDIT' || transaction.type === 'REFUNDED';
    54→  const valueColor = isPositive ? 'PLUS_COLOR_02' : 'BRAND_COMPLEMENT_01';
    55→  const isExpired = transaction.type === 'EXPIRED';
    56→
    57→  return {
    58→    type: 'default' as const,
    59→    bgColor: 'INTENSE_COLOR_01' as const,
    60→    titleColor: 'BRAND_COMPLEMENT_01' as const,
    61→    isSelected: true,
    62→    leftIcon: isExpired ? 'icon-less' : (transaction.icon as PropsIconsNameCore),
    63→    leftIconColor: 'BRAND_COMPLEMENT_01',
    64→    labelBgColor: 'BRAND_COMPLEMENT_03',
    65→    showBackgroundLeftIcon: true,
    66→    title: getCapitalizedText(transaction.description),
    67→    description: undefined,
    68→    value: getFormattedPointsValue(transaction.amount, transaction.type),
    69→    valueColor,
    70→    descriptionSecondary: getTransactionDescription(transaction.type),
    71→    descriptionSecondaryColor: 'INTENSE_COLOR_04',
    72→    showIcon: true,
    73→    rightIcon: 'icon-next',
    74→    showRightIcon: !isExpired,
    75→    onPressDetail: () => {
    76→      eventSelectContent({
    77→        content_type: 'cta',
    78→        content_id: 'detalhe_ponto',
    79→        location_1: 'monetizacao',
    80→        location_2: 'hub_recompensas_spmais',
    81→        location_3: 'extrato_hub_recompensas',
    82→      });
    83→    },
    84→  };
    85→}
    86→
    87→interface GroupedTransactions {
    88→  date: string;
    89→  items: propsItemsListCardTransition[];
    90→}
    91→
    92→function getGroupedTransactionsByDate(
    93→  transactions: PointsTransaction[],
    94→): GroupedTransactions[] {
    95→  if (transactions.length === 0) {
    96→    return [];
    97→  }
    98→
    99→  const sortedTransactions = [...transactions].sort((a, b) =>
   100→    moment(b.date).diff(moment(a.date)),
   101→  );
   102→
   103→  const groupedByDate = sortedTransactions.reduce((acc, transaction) => {
   104→    const formattedDate = getFormattedDateForHeader(transaction.date);
   105→
   106→    if (!acc[formattedDate]) {
   107→      acc[formattedDate] = [];
   108→    }
   109→
   110→    acc[formattedDate].push(
   111→      getTransactionCardItem(transaction) as propsItemsListCardTransition,
   112→    );
   113→    return acc;
   114→  }, {} as Record<string, propsItemsListCardTransition[]>);
   115→
   116→  const getSortedItemsByDate = (
   117→    items: propsItemsListCardTransition[],
   118→    date: string,
   119→  ) => {
   120→    return items.sort((a, b) => {
   121→      const transactionA = sortedTransactions.find(
   122→        (t) =>
   123→          getFormattedDateForHeader(t.date) === date &&
   124→          getTransactionCardItem(t).title === a.title,
   125→      );
   126→      const transactionB = sortedTransactions.find(
   127→        (t) =>
   128→          getFormattedDateForHeader(t.date) === date &&
   129→          getTransactionCardItem(t).title === b.title,
   130→      );
   131→
   132→      if (transactionA && transactionB) {
   133→        return moment(transactionB.date).diff(moment(transactionA.date));
   134→      }
   135→      return 0;
   136→    });
   137→  };
   138→
   139→  const getSortedByDate = (a: GroupedTransactions, b: GroupedTransactions) => {
   140→    const dateA = moment(a.date.split(' ').slice(1).join(' '), 'DD MMMM');
   141→    const dateB = moment(b.date.split(' ').slice(1).join(' '), 'DD MMMM');
   142→    return dateB.diff(dateA);
   143→  };
   144→
   145→  return Object.entries(groupedByDate)
   146→    .map(([date, items]) => ({
   147→      date,
   148→      items: getSortedItemsByDate(items as propsItemsListCardTransition[], date),
   149→    }))
   150→    .sort(getSortedByDate);
   151→}
   152→
   153→class PointsDataGroupedByDayMapper {
   154→  public static getMappedData(
   155→    groupedData: Array<{
   156→      date: string;
   157→      items: propsItemsListCardTransition[];
   158→    }>,
   159→    showLabels = true,
   160→  ): propsItemsListCardTransition[] {
   161→    if (!groupedData || groupedData.length === 0) return [];
   162→
   163→    return groupedData.flatMap(({ date: label, items }) =>
   164→      (items ?? []).map((item, index) => ({
   165→        ...item,
   166→        label,
   167→        showLabel: showLabels ? index === 0 : false,
   168→      })),
   169→    ) as propsItemsListCardTransition[];
   170→  }
   171→}
   172→
   173→function getTransactionFromDto(dto: TransactionDto): PointsTransaction {
   174→  return {
   175→    id: dto.id,
   176→    date: dto.date,
   177→    description: dto.description,
   178→    type: getMappedTransactionType(dto.type),
   179→    amount: dto.amount,
   180→    currencyValue: 0,
   181→    icon: dto.icon,
   182→    details: {
   183→      provider: '',
   184→      extraInfo: '',
   185→      fields: [],
   186→    },
   187→    status: dto.status
   188→  };
   189→}
   190→
   191→export function processPointsExtractData(
   192→  extractData: PointsExtractData | null | undefined,
   193→): ProcessedExtractData {
   194→  if (!extractData || typeof extractData !== 'object') {
   195→    return DEFAULT_PROCESSED_EXTRACT_DATA;
   196→  }
   197→
   198→  try {
   199→    const transactions = extractData.transactions || [];
   200→    const groupedTransactions = getGroupedTransactionsByDate(transactions);
   201→    const mappedTransactions = PointsDataGroupedByDayMapper.getMappedData(groupedTransactions);
   202→
   203→    return {
   204→      groupedTransactions,
   205→      mappedTransactions,
   206→    };
   207→  } catch (error) {
   208→    console.warn('Erro ao processar dados do extrato:', error);
   209→    return DEFAULT_PROCESSED_EXTRACT_DATA;
   210→  }
   211→}
   212→
   213→export function getPointsExtractFromResponse(
   214→  response: Awaited<ReturnType<typeof getPointsExtractApi>>,
   215→): PointsExtractData | null {
   216→  const apiResponse = response?.data;
   217→
   218→  if (!apiResponse) {
   219→    return null;
   220→  }
   221→
   222→  const status = apiResponse.status ?? (apiResponse as any).data?.status;
   223→  const returnCode = status?.returnCode;
   224→
   225→  const transactionsContainer = apiResponse.data ?? apiResponse;
   226→  const transactionsDto = transactionsContainer?.transactions;
   227→  const pagination = apiResponse.pagination ?? (apiResponse as any).data?.pagination;
   228→
   229→  if (!transactionsDto || !Array.isArray(transactionsDto)) {
   230→    return null;
   231→  } 
   232→
   233→  if (!pagination) {
   234→    return null;
   235→  }
   236→
   237→  const transactions = transactionsDto.map(getTransactionFromDto);
   238→
   239→  return {
   240→    transactions,
   241→    pagination,
   242→  };
   243→}
   244→

