import React from 'react';
import { Provider } from 'react-redux';
import { DeepPartial } from 'redux';
import configureMockStore from 'redux-mock-store';

import rootReducers from '../../../src/redux/reducers';

export type RootReducers = DeepPartial<typeof rootReducers>;

const ReduxMockProvider: React.FC<{
  initialState?: RootReducers;
  children: React.ReactNode;
}> = ({ children, initialState = {} }) => {
  const mockStore = configureMockStore([]);
  const store = mockStore(initialState);

  return <Provider store={store}>{children}</Provider>;
};

export default ReduxMockProvider;

/**
 * @deprecated
 * @param {string} category 
 * @param {string} action 
 * @param {string} label 
 */
const _event = (category, action, label) => {};

/**
 * @deprecated
 * @param {string} screenTitle 
 */
export const eventScreenViewV2 = async screenTitle => {};

/**
 * 
 * @param {string} screen_name 
 * @param {string} screen_bussines 
 * @param {string} screen_class
 * @param {{
*  location_1: string
*  location_2: string
*  location_3: string
* }} screen_info 
*/
export const eventScreenViewV3 = async (screen_name, screen_class, screen_bussines, screen_info) => {};

/**
 * @deprecated
 * @param {string} eventName 
 * @param  {...any} eventInfo 
 */
const eventV2 = async (eventName, ...eventInfo) => {};

/**
  * 
  *  @param {string} eventName  
  *  @param {{
*  location_1: string
*  location_2: string
*  location_3: string
* }} eventInfo 
*/
const eventGlobal = async (eventName, eventInfo) => {};

/**
* 
* @param {{
* content_type: string
* content_id?: string
*  location_1: String
*  location_2: String
*  location_3: String
* }} eventInfo 
*/
export const eventSelectContent = async (eventInfo) => {
  if (eventInfo) {
    eventGlobal('select_content', eventInfo);
  }
};

/**
*  
* @param {{
* content_type?: string
* content_id?: string
*  location_1: String
*  location_2: String
*  location_3: String
* }} eventInfo 
*/
const eventServerResponse = async (eventInfo) => {
  if (eventInfo) {
    eventGlobal('server_response', eventInfo);
  }
};

/**
* 
* @param {{
*   value: number
*   currency: string
*   items: [{
*     item_id: string
*     item_name: string
*     item_category: string
*     item_category2: string
*     price: number
*     quantity: number
*     plate: string
*   }]
*   location_1: String
*   location_2: String
*   location_3: String
* }} eventInfo 
*/
const eventViewItem = async (eventInfo) => {
  if (eventInfo) {
    eventGlobal('view_item', eventInfo);
  }
};

/**
* 
* @param {{
*   value: number
*   currency: string
*   items: [{
*     item_id: string
*     item_name: string
*     item_category: string
*     item_category2: string
*     price: number
*     quantity: number
*     plate: string
*     transaction_id: string
*     purchase_cupom: string
*   }]
*   location_1: String
*   location_2: String
*   location_3: String
* }} eventInfo 
*/
const eventPurchase = async (eventInfo) => {
  if (eventInfo) {
    eventGlobal('purchase', eventInfo);
  }
};

const setUserAnalytics = args => {};

const msgAcessTouch = 'Acessar pela sua digital?';
const optionalConfigObject = {
  title: 'Login com digital', // Android
  imageColor: '#e00606', // Android
  imageErrorColor: '#ff0000', // Android
  sensorDescription: msgAcessTouch, // Android
  sensorErrorDescription: 'Error ao tentar vincular', // Android
  cancelText: 'Cancelar', // Android
  fallbackLabel: 'Error ao tentar vincular', // iOS (if empty, then label is hidden)
  unifiedErrors: true, // use unified error messages (default false)
  passcodeFallback: false, // iOS - allows the device to fall back to using the passcode, if faceid/touch is not available. this does not mean that if touchid/faceid fails the first few times it will revert to passcode, rather that if the former are not enrolled, then it will use the passcode.
};

import {
  AccountActionsTypes,
  CustomerActionsTypes,
  auth,
  changeVisibleCarousel,
  checkClientType,
  getCustomerData,
  getData,
  getDataAccount,
  getOpenItems,
  getProducts,
  logout,
  refresh,
  refreshToken,
  requestDeviceInfo,
  resumed,
  saveToken,
  updateAccount,
  updateCustomerData,
  verifyDevice,
} from '@semparar/mf-app-user';
import { NewVehiclesTypes, getVehicles } from '@semparar/mf-app-vehicles';
import { all, takeLatest, takeLeading } from 'redux-saga/effects';

import { Types as PointsTypes } from '../ducks/points';
import { GetMarketplacTypes } from '../ducks/getMarketplace';
import { RescueTypes } from '../ducks/rescue';

import { getPointsBalance } from './points/balance';
import { getPointsProducts } from './points/products';
import { getParameterization } from './points/parameterization';
import { getInitialPointsData } from './points/initialData';
import { getMarketplace } from './marketplace/getMarketplace';
import { postRescue } from './rescue';

export const FintechCardHomeSagas = [
  takeLatest(PointsTypes.REQUEST_BALANCE, getPointsBalance),
  takeLatest(PointsTypes.REQUEST_PRODUCTS, getPointsProducts),
  takeLatest(PointsTypes.REQUEST_PARAMETERIZATION, getParameterization),
  takeLatest(PointsTypes.REQUEST_INITIAL_DATA, getInitialPointsData),
  takeLatest(GetMarketplacTypes.REQUEST_GET_MARKETPLACE, getMarketplace),
  takeLeading(RescueTypes.REQUEST, postRescue),
];

function* rootSaga() {
  return yield all([
    takeLatest(CustomerActionsTypes.GET_DATA, getData),
    takeLatest(CustomerActionsTypes.REQUEST_RESUMED, resumed),
    takeLatest(CustomerActionsTypes.REQUEST_DEVICE_VERIFY, verifyDevice),
    takeLatest(CustomerActionsTypes.LOGOUT, logout),
    takeLatest(CustomerActionsTypes.REQUEST_DEVICE_INFO, requestDeviceInfo),
    takeLatest(CustomerActionsTypes.CHANGE_VISIBLE_CAROUSEL, changeVisibleCarousel),
    takeLatest(CustomerActionsTypes.AUTH, auth),
    takeLatest(CustomerActionsTypes.REFRESH, refresh),
    takeLatest(CustomerActionsTypes.REFRESH_TOKEN, refreshToken),
    takeLatest(CustomerActionsTypes.SAVE_TOKEN, saveToken),
    takeLatest(AccountActionsTypes.GET_DATA, getDataAccount),
    takeLatest(AccountActionsTypes.UPDATE_DATA, updateAccount),
    takeLatest(AccountActionsTypes.REQUEST_OPEN_BALANCE, getOpenItems),
    takeLatest(CustomerActionsTypes.CHECK_CLIENT_TYPE, checkClientType),
    takeLatest(CustomerActionsTypes.REQUEST_CUSTOMER_DATA, getCustomerData),
    takeLatest(CustomerActionsTypes.UPDATE_CUSTOMER_DATA, updateCustomerData),
    takeLatest(CustomerActionsTypes.GET_PRODUCTS, getProducts),
    takeLatest(NewVehiclesTypes.GET_VEHICLES_REQUEST, getVehicles),

    ...FintechCardHomeSagas,
  ]);
}

