  requestDeviceInfo,
  resumed,
  saveToken,
  updateAccount,
  updateCustomerData,
  verifyDevice,
} from '@semparar/mf-app-user';
import { NewVehiclesTypes, getVehicles } from '@semparar/mf-app-vehicles';
import { all, takeLatest, takeLeading } from 'redux-saga/effects';

import { Types as PointsTypes } from '../ducks/points';
import { GetMarketplacTypes } from '../ducks/getMarketplace';
import { RescueTypes } from '../ducks/rescue';

import { getPointsBalance } from './points/balance';
import { getPointsProducts } from './points/products';
import { getParameterization } from './points/parameterization';
import { getInitialPointsData } from './points/initialData';
import { getMarketplace } from './marketplace/getMarketplace';
import { postRescue } from './rescue';

export const FintechCardHomeSagas = [
  takeLatest(PointsTypes.REQUEST_BALANCE, getPointsBalance),
  takeLatest(PointsTypes.REQUEST_PRODUCTS, getPointsProducts),
  takeLatest(PointsTypes.REQUEST_PARAMETERIZATION, getParameterization),
  takeLatest(PointsTypes.REQUEST_INITIAL_DATA, getInitialPointsData),
  takeLatest(GetMarketplacTypes.REQUEST_GET_MARKETPLACE, getMarketplace),
  takeLeading(RescueTypes.REQUEST, postRescue),
];

function* rootSaga() {
  return yield all([
    takeLatest(CustomerActionsTypes.GET_DATA, getData),
    takeLatest(CustomerActionsTypes.REQUEST_RESUMED, resumed),
    takeLatest(CustomerActionsTypes.REQUEST_DEVICE_VERIFY, verifyDevice),
    takeLatest(CustomerActionsTypes.LOGOUT, logout),
    takeLatest(CustomerActionsTypes.REQUEST_DEVICE_INFO, requestDeviceInfo),
    takeLatest(CustomerActionsTypes.CHANGE_VISIBLE_CAROUSEL, changeVisibleCarousel),
    takeLatest(CustomerActionsTypes.AUTH, auth),
    takeLatest(CustomerActionsTypes.REFRESH, refresh),
    takeLatest(CustomerActionsTypes.REFRESH_TOKEN, refreshToken),
    takeLatest(CustomerActionsTypes.SAVE_TOKEN, saveToken),
    takeLatest(AccountActionsTypes.GET_DATA, getDataAccount),
    takeLatest(AccountActionsTypes.UPDATE_DATA, updateAccount),
    takeLatest(AccountActionsTypes.REQUEST_OPEN_BALANCE, getOpenItems),
    takeLatest(CustomerActionsTypes.CHECK_CLIENT_TYPE, checkClientType),
    takeLatest(CustomerActionsTypes.REQUEST_CUSTOMER_DATA, getCustomerData),
    takeLatest(CustomerActionsTypes.UPDATE_CUSTOMER_DATA, updateCustomerData),
    takeLatest(CustomerActionsTypes.GET_PRODUCTS, getProducts),
    takeLatest(NewVehiclesTypes.GET_VEHICLES_REQUEST, getVehicles),

    ...FintechCardHomeSagas,
  ]);
}

